// 檢查 Gemini API Key 是否已設定
const GEMINI_KEY = '在此填入你的_GEMINI_API_KEY';
const hasGeminiKey = GEMINI_KEY !== '在此填入你的' + '_GEMINI_API_KEY';

const output = $json.output;
const original = $('只取第一筆').first().json;
const keyword = original['關鍵字'];

// 若無 Gemini Key，跳過圖片流程
if (!hasGeminiKey) {
  return [{
    json: {
      skip_images: true,
      article: {
        title: output.title,
        slug: output.slug,
        content: output.content,
        excerpt: output.excerpt
      },
      seo: output.seo,
      original: {
        keyword: keyword,
        title: original['標題'] || '',
        row_number: original['row_number']
      }
    }
  }];
}

// 確保 image_prompts 是陣列且有 3 個元素
const imagePrompts = output.image_prompts || [];
while (imagePrompts.length < 3) {
  imagePrompts.push('Professional blog illustration, modern clean style, 1200x630');
}

// 確保 image_alts 是陣列且有 3 個元素（含關鍵字的 fallback）
const imageAlts = output.image_alts || [];
while (imageAlts.length < 3) {
  const fallbackAlt = imageAlts.length === 0 ? `${keyword} - 專業圖解說明` : `${output.title} - 圖${imageAlts.length + 1}`;
  imageAlts.push(fallbackAlt);
}

// 產生 3 筆資料，每筆對應一張圖片
const items = [];
for (let i = 0; i < 3; i++) {
  items.push({
    json: {
      skip_images: false,
      index: i,
      image_prompt: imagePrompts[i],
      image_alt: imageAlts[i],
      article: {
        title: output.title,
        slug: output.slug,
        content: output.content,
        excerpt: output.excerpt
      },
      seo: output.seo,
      original: {
        keyword: keyword,
        title: original['標題'] || '',
        row_number: original['row_number']
      }
    }
  });
}

return items;

// 無圖片模式：準備文章資料直接送 WP
const data = $('拆分圖片任務').first().json;

return [{
  json: {
    article: data.article,
    seo: data.seo,
    original: data.original,
    images: [],
    wp_media: {
      id: 0
    }
  }
}];

