// 從 Gemini 回應取得 base64 圖片
const response = $input.first().json;
const prevData = $('批次處理圖片').first().json;

let base64Image = null;
let mimeType = 'image/png';

// 解析 Gemini 回應結構
if (response.candidates && response.candidates[0]) {
  const parts = response.candidates[0].content.parts;
  for (const part of parts) {
    if (part.inlineData) {
      base64Image = part.inlineData.data;
      mimeType = part.inlineData.mimeType || 'image/png';
      break;
    }
  }
}

if (!base64Image) {
  throw new Error('Gemini 未回傳圖片');
}

const extension = mimeType.split('/')[1] || 'png';
const fileName = `${prevData.article.slug}-img${prevData.index + 1}.${extension}`;

return [{
  json: {
    index: prevData.index,
    article: prevData.article,
    seo: prevData.seo,
    original: prevData.original,
    image: {
      fileName: fileName,
      mimeType: mimeType
    }
  },
  binary: {
    image: {
      data: base64Image,
      mimeType: mimeType,
      fileName: fileName
    }
  }
}];

// 記錄這張圖片的結果
const gdriveResult = $input.first().json;
const imageData = $('轉換圖片格式').first();
const loopData = $('批次處理圖片').first().json;

const gdriveFileId = $('上傳 Google Drive').first().json.id;
const gdriveUrl = `https://drive.google.com/uc?id=${gdriveFileId}&export=view`;

return [{
  json: {
    index: loopData.index,
    article: loopData.article,
    seo: loopData.seo,
    original: loopData.original,
    image_result: {
      index: loopData.index,
      gdrive_id: gdriveFileId,
      gdrive_url: gdriveUrl,
      fileName: imageData.json.image.fileName,
      mimeType: imageData.json.image.mimeType,
      alt: loopData.image_alt
    }
  },
  binary: imageData.binary
}];

// 收集所有 3 張圖片的結果
const allItems = $('記錄圖片結果').all();

// 按 index 排序
const sortedItems = allItems.sort((a, b) => a.json.index - b.json.index);

// 取得文章資料（從第一筆）
const article = sortedItems[0].json.article;
const seo = sortedItems[0].json.seo;
const original = sortedItems[0].json.original;

// 收集所有圖片 URL
const imageResults = sortedItems.map(item => item.json.image_result);

// 將圖片插入到文章的前三個 H2 段落後面
let content = article.content;

// 找出所有 H2 段落的結束位置（找 </h2> 後面的第一個 </p> 或段落結束）
const h2Regex = /<h2[^>]*>.*?<\/h2>/gi;
let h2Matches = [];
let match;
while ((match = h2Regex.exec(content)) !== null) {
  h2Matches.push({ index: match.index, length: match[0].length, end: match.index + match[0].length });
}

// 在前三個 H2 後面找到適合插入圖片的位置（該段落的結尾）
// 策略：在每個 H2 後找到下一個 H2 或文章結尾之前的位置
const insertPositions = [];
for (let i = 0; i < Math.min(3, h2Matches.length); i++) {
  const currentH2End = h2Matches[i].end;
  const nextH2Start = h2Matches[i + 1] ? h2Matches[i + 1].index : content.length;

  // 在這個區間內找最後一個 </p>、</ul>、</table>、</details> 作為插入點
  const sectionContent = content.substring(currentH2End, nextH2Start);
  const lastTagMatch = sectionContent.match(/.*(<\/p>|<\/ul>|<\/table>|<\/details>)/s);

  if (lastTagMatch) {
    const insertPos = currentH2End + lastTagMatch[0].length;
    insertPositions.push(insertPos);
  } else {
    // 如果找不到，就插在 H2 結束後
    insertPositions.push(currentH2End);
  }
}

// 從後往前插入圖片（避免位置偏移）
for (let i = insertPositions.length - 1; i >= 0; i--) {
  if (imageResults[i]) {
    // 使用 Claude 產生的 SEO alt 文字
    const altText = imageResults[i].alt || `${article.title} - 圖${i + 1}`;
    const imgTag = `\n<figure class="wp-block-image size-large"><img src="${imageResults[i].gdrive_url}" alt="${altText}" /></figure>\n`;
    content = content.slice(0, insertPositions[i]) + imgTag + content.slice(insertPositions[i]);
  }
}

// 第一張圖的 binary 資料（用於 WP 精選圖片）
const firstImageBinary = sortedItems[0].binary;

return [{
  json: {
    article: {
      ...article,
      content: content  // 已插入圖片的 content
    },
    seo: seo,
    original: original,
    images: imageResults,
    featured_image: imageResults[0]  // 第一張當精選圖片
  },
  binary: firstImageBinary
}];

