parameters.jsCode:
// 準備 Rank Math SEO 更新資料
const wpPost = $input.first().json;
let prevData;
try {
  prevData = $('合併 Media 結果').first().json;
} catch (e) {
  prevData = $('準備無圖文章').first().json;
}

return [{
  json: {
    post_id: wpPost.id,
    post_link: wpPost.link,
    article: prevData.article,
    seo: prevData.seo,
    original: prevData.original,
    images: prevData.images || [],
    wp_media: prevData.wp_media || { id: 0 }
  }
}];

// 最終輸出摘要 - 包含回填 Google Sheets 所需的欄位
const prevData = $input.first().json;

// 取得 WP base URL
let editUrl = null;
try {
  if (prevData.post_link) {
    const wpBaseUrl = new URL(prevData.post_link).origin;
    editUrl = `${wpBaseUrl}/wp-admin/post.php?post=${prevData.post_id}&action=edit`;
  }
} catch(e) {}

// 台北時區的日期時間
const now = new Date();
const taipeiDate = now.toLocaleString('zh-TW', { 
  timeZone: 'Asia/Taipei',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hour12: false
}).replace(/\//g, '-');

// 收集所有圖片 URL
const imageCount = (prevData.images || []).length;
const imageUrls = (prevData.images || []).map(img => img.gdrive_url);

const imageMsg = imageCount > 0 ? `含 ${imageCount} 張圖片` : '純文字，無圖片';

return [{
  json: {
    // Google Sheets 更新用欄位
    row_number: prevData.original.row_number,
    狀態: '已完成',
    日期: taipeiDate,
    // 詳細資訊
    status: 'success',
    message: `文章已建立並完成 SEO 設定（${imageMsg}）`,
    title: prevData.article.title,
    keyword: prevData.original.keyword,
    wordpress: {
      post_id: prevData.post_id,
      post_url: prevData.post_link,
      edit_url: editUrl,
      featured_image: (prevData.wp_media || {}).url || null
    },
    seo: {
      title: prevData.seo.title,
      description: prevData.seo.description,
      focus_keyword: prevData.seo.focus_keyword,
      secondary_keywords: prevData.seo.secondary_keywords || '',
      rank_math_updated: true
    },
    images: {
      count: imageCount,
      urls: imageUrls
    }
  }
}];

// 最終完成訊息
const result = $('輸出結果').first().json;

return [{
  json: {
    ...result,
    sheet_updated: true,
    completed_at: new Date().toISOString()
  }
}];

